// Format Source Pack JSON
const inputParams = $('Set Input Parameters').first().json;
const peptideName = inputParams.peptideName;
const category = inputParams.category;
const aliasesStr = inputParams.aliases;

// Parse aliases
const aliases = aliasesStr ? aliasesStr.split(',').map(a => a.trim()).filter(a => a) : [];

// Get data from previous nodes
let pubmedXml = '';
let europepmcData = null;
let clinicalTrialsData = null;

try {
  pubmedXml = $('PubMed Fetch Details').first().json.data || '';
} catch (e) {
  console.log('No PubMed data');
}

try {
  europepmcData = $('Europe PMC Search').first().json;
} catch (e) {
  console.log('No Europe PMC data');
}

try {
  clinicalTrialsData = $('ClinicalTrials.gov Search').first().json;
} catch (e) {
  console.log('No ClinicalTrials data');
}

const sources = [];
const seenIds = new Set();

// Parse PubMed XML (simplified - in production use proper XML parser)
if (pubmedXml) {
  const pmidMatches = pubmedXml.match(/<PMID[^>]*>(\d+)<\/PMID>/g) || [];
  const titleMatches = pubmedXml.match(/<ArticleTitle>([^<]+)<\/ArticleTitle>/g) || [];
  const yearMatches = pubmedXml.match(/<PubDate>[\s\S]*?<Year>(\d{4})<\/Year>[\s\S]*?<\/PubDate>/g) || [];
  const journalMatches = pubmedXml.match(/<Title>([^<]+)<\/Title>/g) || [];

  for (let i = 0; i < Math.min(pmidMatches.length, 20); i++) {
    const pmid = pmidMatches[i]?.match(/<PMID[^>]*>(\d+)<\/PMID>/)?.[1];
    const title = titleMatches[i]?.match(/<ArticleTitle>([^<]+)<\/ArticleTitle>/)?.[1] || 'Unknown Title';
    const year = yearMatches[i]?.match(/<Year>(\d{4})<\/Year>/)?.[1] || new Date().getFullYear();
    const journal = journalMatches[i]?.match(/<Title>([^<]+)<\/Title>/)?.[1] || 'Unknown Journal';

    if (pmid && !seenIds.has(`PMID:${pmid}`)) {
      seenIds.add(`PMID:${pmid}`);
      sources.push({
        id: `PMID:${pmid}`,
        type: 'pubmed',
        title: title,
        authors: [],
        journal: journal,
        year: parseInt(year),
        studyType: 'review',
        subjects: 'human',
        sampleSize: null,
        openAccess: false,
        url: `https://pubmed.ncbi.nlm.nih.gov/${pmid}/`,
        abstract: ''
      });
    }
  }
}

// Parse Europe PMC results
if (europepmcData?.resultList?.result) {
  for (const article of europepmcData.resultList.result.slice(0, 10)) {
    const id = article.pmid ? `PMID:${article.pmid}` : (article.doi ? `DOI:${article.doi}` : null);
    if (id && !seenIds.has(id)) {
      seenIds.add(id);
      sources.push({
        id: id,
        type: 'europePMC',
        title: article.title || 'Unknown Title',
        authors: article.authorString ? article.authorString.split(', ').slice(0, 5) : [],
        journal: article.journalTitle || 'Unknown Journal',
        year: parseInt(article.pubYear) || new Date().getFullYear(),
        studyType: article.pubType?.includes('review') ? 'review' : 'observational',
        subjects: 'human',
        sampleSize: null,
        openAccess: article.isOpenAccess === 'Y',
        url: article.pmid ? `https://pubmed.ncbi.nlm.nih.gov/${article.pmid}/` : `https://doi.org/${article.doi}`,
        abstract: article.abstractText || ''
      });
    }
  }
}

// Parse Clinical Trials
const trials = [];
if (clinicalTrialsData?.studies) {
  for (const study of clinicalTrialsData.studies.slice(0, 10)) {
    const protocol = study.protocolSection;
    if (protocol) {
      const nctId = protocol.identificationModule?.nctId;
      if (nctId) {
        // Map status
        const statusMap = {
          'RECRUITING': 'recruiting',
          'ACTIVE_NOT_RECRUITING': 'active',
          'COMPLETED': 'completed',
          'TERMINATED': 'terminated',
          'WITHDRAWN': 'withdrawn',
          'NOT_YET_RECRUITING': 'not-yet-recruiting',
          'ENROLLING_BY_INVITATION': 'enrolling-by-invitation',
          'SUSPENDED': 'suspended'
        };

        const phaseMap = {
          'PHASE1': '1',
          'PHASE2': '2',
          'PHASE3': '3',
          'PHASE4': '4',
          'PHASE1_PHASE2': '1/2',
          'PHASE2_PHASE3': '2/3',
          'NA': 'not-applicable'
        };

        trials.push({
          nctId: nctId,
          title: protocol.identificationModule?.briefTitle || 'Unknown Trial',
          status: statusMap[protocol.statusModule?.overallStatus] || 'unknown',
          phase: phaseMap[protocol.designModule?.phases?.[0]] || 'not-applicable',
          conditions: protocol.conditionsModule?.conditions || [],
          interventions: protocol.armsInterventionsModule?.interventions?.map(i => i.name) || [],
          enrollmentTarget: protocol.designModule?.enrollmentInfo?.count || 0,
          startDate: protocol.statusModule?.startDateStruct?.date || null,
          completionDate: protocol.statusModule?.completionDateStruct?.date || null
        });
      }
    }
  }
}

// Count sources
const humanStudies = sources.filter(s => s.subjects === 'human').length;
const preclinicalStudies = sources.filter(s => s.subjects === 'animal' || s.subjects === 'in-vitro').length;
const openAccessCount = sources.filter(s => s.openAccess).length;

// Build source pack
const sourcePack = {
  peptide: {
    name: peptideName,
    aliases: aliases,
    category: category
  },
  sources: sources,
  trials: trials,
  metadata: {
    generatedAt: new Date().toISOString(),
    sourceCounts: {
      total: sources.length,
      human: humanStudies,
      preclinical: preclinicalStudies,
      openAccess: openAccessCount
    }
  }
};

return {
  json: {
    sourcePack: sourcePack,
    peptideName: peptideName,
    fileName: `${peptideName.toLowerCase().replace(/\s+/g, '-')}.json`
  }
};
